import { Api, type Session, type Participant, type Track, type Project } from './api';
import { Room } from './room';

export interface RecorderClientOptions {
  apiBase?: string;
  /** A personal API token (`pat_...`), generated from the dashboard's API tokens page. */
  token: string;
}

/**
 * Host-side session management, authenticated with a personal API token —
 * this is what a Foundry module, a script, or any integration outside our
 * own web app uses to create and control sessions. Same permissions a
 * logged-in host has on the dashboard: only their own sessions.
 *
 * To also record the host's own camera/screen, join a Room the normal
 * way (joinRoom below, or Room.join directly) — hosting and
 * participating are separate identities that can coexist.
 */
export class RecorderClient {
  private readonly api: Api;
  private readonly apiBase: string;

  constructor(opts: RecorderClientOptions) {
    this.apiBase = opts.apiBase ?? '';
    this.api = new Api(this.apiBase, undefined, opts.token);
  }

  /** Pass a projectId to see only that project's sessions — the convention
   *  for modules is one project named after the module (see ensureProject). */
  listSessions(projectId?: string): Promise<{ sessions: Session[] }> {
    return this.api.listSessions(projectId);
  }
  createSession(name: string, projectId?: string): Promise<{ session: Session }> {
    return this.api.createSession(name, projectId);
  }
  /**
   * Find-or-create a project by exact name. Modules call this once with
   * their own name and keep every session inside it, so the host's other
   * sessions (podcasts, other tools) never mix into the module's list.
   */
  async ensureProject(name: string): Promise<Project> {
    const { projects } = await this.api.listProjects();
    const existing = projects.find((p) => p.name === name);
    if (existing) return existing;
    const { project } = await this.api.createProject(name);
    return project;
  }
  getSession(id: string): Promise<{ session: Session; participants: Participant[]; tracks: Track[] }> {
    return this.api.getSession(id);
  }
  /** Requires confirmName to exactly match the session's name. */
  deleteSession(id: string, confirmName: string): Promise<{ ok: true }> {
    return this.api.deleteSession(id, confirmName);
  }
  /** Undo a pending deletion inside the grace period. */
  restoreSession(id: string): Promise<{ ok: true }> {
    return this.api.restoreSession(id);
  }
  startRecording(sessionId: string): Promise<{ ok: true }> {
    return this.api.startSession(sessionId);
  }
  stopRecording(sessionId: string): Promise<{ ok: true }> {
    return this.api.endSession(sessionId);
  }
  /** Stops recording (if running) AND disconnects every participant from the live call. */
  closeForEveryone(sessionId: string): Promise<{ ok: true }> {
    return this.api.closeSession(sessionId);
  }
  rotateInvite(sessionId: string): Promise<{ invite_token: string }> {
    return this.api.rotateInvite(sessionId);
  }
  /** Host-enforced mute/hide — the target participant's client applies it to their own recording. */
  setParticipantControls(sessionId: string, participantId: string, controls: { micMuted?: boolean; camMuted?: boolean }): Promise<{ ok: true }> {
    return this.api.setParticipantControls(sessionId, participantId, controls);
  }
  /** A time-limited signed download link for one completed track. */
  getDownloadUrl(trackId: string): Promise<{ url: string }> {
    return this.api.downloadUrl(trackId);
  }

  /** Join this session's live room as a participant — e.g. the host recording their own camera. */
  joinRoom(inviteToken: string, displayName: string): Promise<Room> {
    return Room.join({ apiBase: this.apiBase, inviteToken, displayName });
  }
}
