import type { PartStore, TrackManifest } from './types';

/** In-memory store: used in tests and as a fallback when OPFS is unavailable. */
export class MemoryPartStore implements PartStore {
  private parts = new Map<string, Uint8Array[]>();
  private manifests = new Map<string, TrackManifest>();

  private key(trackId: string, partNumber: number): string {
    return `${trackId}/${partNumber}`;
  }

  async appendCurrent(trackId: string, partNumber: number, data: Uint8Array): Promise<void> {
    const k = this.key(trackId, partNumber);
    const existing = this.parts.get(k) ?? [];
    existing.push(data.slice());
    this.parts.set(k, existing);
  }

  async readPart(trackId: string, partNumber: number): Promise<Uint8Array | null> {
    const segments = this.parts.get(this.key(trackId, partNumber));
    if (!segments) return null;
    const total = segments.reduce((n, s) => n + s.length, 0);
    const out = new Uint8Array(total);
    let offset = 0;
    for (const s of segments) {
      out.set(s, offset);
      offset += s.length;
    }
    return out;
  }

  async deletePart(trackId: string, partNumber: number): Promise<void> {
    this.parts.delete(this.key(trackId, partNumber));
  }

  async readManifest(trackId: string): Promise<TrackManifest | null> {
    const m = this.manifests.get(trackId);
    return m ? structuredClone(m) : null;
  }

  async writeManifest(trackId: string, manifest: TrackManifest): Promise<void> {
    this.manifests.set(trackId, structuredClone(manifest));
  }

  async deleteTrack(trackId: string): Promise<void> {
    this.manifests.delete(trackId);
    for (const k of [...this.parts.keys()]) {
      if (k.startsWith(`${trackId}/`)) this.parts.delete(k);
    }
  }
}

/**
 * OPFS-backed store. Layout: tracks/{trackId}/manifest.json and
 * tracks/{trackId}/part-{n}.bin. Survives page reloads and browser
 * restarts, which is what makes uploads resumable.
 */
export class OpfsPartStore implements PartStore {
  private root: FileSystemDirectoryHandle | null = null;

  static isSupported(): boolean {
    return typeof navigator !== 'undefined' && !!navigator.storage?.getDirectory;
  }

  private async trackDir(trackId: string, create: boolean): Promise<FileSystemDirectoryHandle | null> {
    try {
      if (!this.root) {
        const opfs = await navigator.storage.getDirectory();
        this.root = await opfs.getDirectoryHandle('tracks', { create: true });
      }
      return await this.root.getDirectoryHandle(trackId, { create });
    } catch {
      return null;
    }
  }

  async appendCurrent(trackId: string, partNumber: number, data: Uint8Array): Promise<void> {
    const dir = await this.trackDir(trackId, true);
    if (!dir) throw new Error('OPFS unavailable');
    const file = await dir.getFileHandle(`part-${partNumber}.bin`, { create: true });
    const existing = await file.getFile();
    const writable = await file.createWritable({ keepExistingData: true });
    await writable.write({ type: 'write', position: existing.size, data: data.slice().buffer as ArrayBuffer });
    await writable.close();
  }

  async readPart(trackId: string, partNumber: number): Promise<Uint8Array | null> {
    const dir = await this.trackDir(trackId, false);
    if (!dir) return null;
    try {
      const file = await dir.getFileHandle(`part-${partNumber}.bin`);
      const blob = await file.getFile();
      return new Uint8Array(await blob.arrayBuffer());
    } catch {
      return null;
    }
  }

  async deletePart(trackId: string, partNumber: number): Promise<void> {
    const dir = await this.trackDir(trackId, false);
    if (!dir) return;
    try {
      await dir.removeEntry(`part-${partNumber}.bin`);
    } catch {
      /* already gone */
    }
  }

  async readManifest(trackId: string): Promise<TrackManifest | null> {
    const dir = await this.trackDir(trackId, false);
    if (!dir) return null;
    try {
      const file = await dir.getFileHandle('manifest.json');
      const blob = await file.getFile();
      return JSON.parse(await blob.text()) as TrackManifest;
    } catch {
      return null;
    }
  }

  async writeManifest(trackId: string, manifest: TrackManifest): Promise<void> {
    const dir = await this.trackDir(trackId, true);
    if (!dir) throw new Error('OPFS unavailable');
    const file = await dir.getFileHandle('manifest.json', { create: true });
    const writable = await file.createWritable();
    await writable.write(JSON.stringify(manifest));
    await writable.close();
  }

  async deleteTrack(trackId: string): Promise<void> {
    const dir = await this.trackDir(trackId, false);
    if (!dir || !this.root) return;
    try {
      await this.root.removeEntry(trackId, { recursive: true });
    } catch {
      /* already gone */
    }
  }
}
