/**
 * WebSocket to the session's Durable Object room. Pushes the same roster
 * payload the poll endpoint serves, in milliseconds. Reconnects with
 * backoff; the caller keeps a slow poll as fallback, so a dead socket
 * degrades to "slightly stale", never "broken".
 */
export interface RoomSocket {
  close(): void;
  isConnected(): boolean;
}

export function connectRoomSocket(
  sessionId: string,
  joinToken: string,
  onMessage: (payload: unknown) => void,
  apiBase = '',
): RoomSocket {
  let ws: WebSocket | null = null;
  let closed = false;
  let attempts = 0;
  let heartbeat: ReturnType<typeof setInterval> | null = null;

  const base = apiBase || location.origin;
  const url = `${base.replace(/^http/, 'ws')}/v1/rooms/${sessionId}/ws?token=${encodeURIComponent(joinToken)}`;

  function open() {
    if (closed) return;
    ws = new WebSocket(url);
    ws.onopen = () => {
      attempts = 0;
      // Heartbeat: lets the room detect dead sockets (phone lock, network
      // drop) in ~12-15s. The UI reacts even faster via track mute events.
      heartbeat = setInterval(() => {
        if (ws?.readyState === WebSocket.OPEN) ws.send('ping');
      }, 4_000);
    };
    ws.onmessage = (e) => {
      if (typeof e.data !== 'string' || e.data === 'pong') return;
      try {
        onMessage(JSON.parse(e.data));
      } catch {
        /* non-JSON frame */
      }
    };
    ws.onclose = () => {
      ws = null;
      if (heartbeat) clearInterval(heartbeat);
      heartbeat = null;
      if (closed) return;
      attempts += 1;
      setTimeout(open, Math.min(1000 * 2 ** attempts, 15_000));
    };
    ws.onerror = () => ws?.close();
  }

  open();

  return {
    close() {
      closed = true;
      if (heartbeat) clearInterval(heartbeat);
      heartbeat = null;
      const socket = ws;
      if (!socket) return;
      // Closing a CONNECTING socket logs a browser warning (common under
      // React StrictMode double-mount) — wait for open, then close.
      if (socket.readyState === WebSocket.CONNECTING) {
        socket.onopen = () => socket.close();
      } else {
        socket.close();
      }
    },
    isConnected: () => ws?.readyState === WebSocket.OPEN,
  };
}
