import type { UploadProgress, UploadTransport } from './types';
import { ChunkBuffer } from './buffer';

export interface UploaderOptions {
  /** How long to wait when no sealed part is ready yet. */
  idleDelayMs?: number;
  /** Base delay for exponential backoff after a failed upload. */
  retryBaseMs?: number;
  /** Give up after this many consecutive failures on the same part. */
  maxRetries?: number;
  onProgress?: (p: UploadProgress) => void;
}

const sleep = (ms: number) => new Promise<void>((r) => setTimeout(r, ms));

/**
 * Drains sealed parts from a ChunkBuffer to the server, in order, one at a
 * time. Survives transient failures with backoff; reconciles with the
 * server on start so a resumed session never re-uploads confirmed parts.
 * Runs until the buffer is finished and fully uploaded, then completes the
 * track. No events, no shared state: one loop owns the whole lifecycle.
 */
export class Uploader {
  private stopped = false;
  private completed = false;

  constructor(
    private readonly buffer: ChunkBuffer,
    private readonly transport: UploadTransport,
    private readonly opts: UploaderOptions = {},
  ) {}

  private emit(inFlightBytes = 0): void {
    const s = this.buffer.state;
    this.opts.onProgress?.({
      trackId: s.trackId,
      bytesRecorded: s.bytesRecorded,
      bytesUploaded: s.bytesUploaded + inFlightBytes,
      uploadedParts: s.uploaded.length,
      sealedParts: s.sealedThrough,
      finished: s.finished,
      completed: this.completed,
    });
  }

  /** Ask the server which parts it already has and mark them locally. */
  private async reconcile(): Promise<void> {
    const remote = await this.transport.remoteParts(this.buffer.state.trackId);
    const local = new Set(this.buffer.state.uploaded);
    for (const p of remote) {
      if (local.has(p)) continue;
      const data = await this.buffer.readPart(p);
      await this.buffer.markUploaded(p, data?.length ?? this.buffer.state.partSizeBytes);
    }
  }

  async run(): Promise<void> {
    const idle = this.opts.idleDelayMs ?? 500;
    const retryBase = this.opts.retryBaseMs ?? 1000;
    const maxRetries = this.opts.maxRetries ?? 8;

    await this.reconcile();
    this.emit();

    while (!this.stopped) {
      const next = this.buffer.sealedUnuploaded()[0];

      if (next === undefined) {
        if (this.buffer.state.finished) break;
        await sleep(idle);
        continue;
      }

      const data = await this.buffer.readPart(next);
      if (data === null) {
        throw new Error(`part ${next} missing from local store (trackId=${this.buffer.state.trackId})`);
      }

      let attempt = 0;
      for (;;) {
        if (this.stopped) return;
        try {
          await this.transport.uploadPart(this.buffer.state.trackId, next, data, this.buffer.isFinalPart(next), (sent) =>
            this.emit(Math.min(sent, data.length)),
          );
          await this.buffer.markUploaded(next, data.length);
          this.emit();
          break;
        } catch (err) {
          attempt += 1;
          if (attempt > maxRetries) throw err;
          await sleep(retryBase * 2 ** (attempt - 1));
        }
      }
    }

    if (!this.stopped && this.buffer.allUploaded()) {
      await this.transport.completeTrack(this.buffer.state.trackId);
      this.completed = true;
      this.emit();
    }
  }

  /** Pause draining; a later run() picks up from the manifest. */
  stop(): void {
    this.stopped = true;
  }
}
