/** Minimal typed pub/sub — no dependency pulled in just for events. Define the event map as a `type`, not an `interface`. */
export class Emitter<Events extends Record<string, (...args: any[]) => void>> {
  private listeners: { [K in keyof Events]?: Set<Events[K]> } = {};

  on<K extends keyof Events>(event: K, cb: Events[K]): () => void {
    (this.listeners[event] ??= new Set()).add(cb);
    return () => this.listeners[event]?.delete(cb);
  }

  protected emit<K extends keyof Events>(event: K, ...args: Parameters<Events[K]>): void {
    this.listeners[event]?.forEach((cb) => (cb as (...a: Parameters<Events[K]>) => void)(...args));
  }
}
