/**
 * WebRTC client for the Cloudflare Serverless SFU, reached through the
 * Worker proxy (/v1/realtime/*) so the app secret never touches the
 * browser. One RTCPeerConnection carries everything: local tracks are
 * published under stable names (cam-video, cam-audio, screen-video,
 * screen-audio) and remote tracks are pulled by (sessionId, trackName)
 * pairs learned from the roster.
 */

interface SfuTrackResult {
  mid?: string;
  trackName?: string;
  sessionId?: string;
  error?: string;
}

interface SfuResponse {
  sessionId?: string;
  sessionDescription?: { sdp: string; type: 'offer' | 'answer' };
  requiresImmediateRenegotiation?: boolean;
  tracks?: SfuTrackResult[];
  errorCode?: string;
  errorDescription?: string;
}

export interface RemoteTrack {
  participantKey: string;
  trackName: string;
  stream: MediaStream;
  kind: string;
}

/**
 * The live call is a preview; the recording is the product. Cap what we
 * publish so phones can decode it and upload bandwidth stays free for
 * recording chunks. Local MediaRecorder reads the raw track directly and
 * is completely unaffected by these caps.
 */
// Keyed by prefix family (share prefixes are unique per share: screen1, screen2…).
const PUBLISH_LIMITS: { match: (name: string) => boolean; maxBitrate: number; scaleResolutionDownBy?: number; maxFramerate?: number }[] = [
  { match: (n) => n.startsWith('cam') && n.endsWith('-video'), maxBitrate: 700_000, scaleResolutionDownBy: 2, maxFramerate: 24 },
  { match: (n) => n.startsWith('screen') && n.endsWith('-video'), maxBitrate: 1_200_000, maxFramerate: 15 },
];

export class RtcClient {
  private pc: RTCPeerConnection | null = null;
  sessionId: string | null = null;
  private pendingMids = new Map<string, { participantKey: string; trackName: string }>();
  private publishedMids = new Map<string, string>();
  private publishedSenders = new Map<string, RTCRtpSender>();
  private pulledKeys = new Set<string>();
  private queue: Promise<unknown> = Promise.resolve();
  onRemoteTrack: ((t: RemoteTrack) => void) | null = null;
  /** Fires within ~1-2s when a remote track's packets stop (publisher died,
   *  tab froze, network drop) and again when they resume. */
  onRemoteTrackLive: ((participantKey: string, trackName: string, live: boolean) => void) | null = null;

  constructor(
    private readonly joinToken: string,
    private readonly apiBase = '',
  ) {}

  private async sfu(path: string, body?: unknown, method = 'POST'): Promise<SfuResponse> {
    const headers: Record<string, string> = { authorization: `Bearer ${this.joinToken}` };
    if (body !== undefined) headers['content-type'] = 'application/json';
    const res = await fetch(`${this.apiBase}/v1/realtime${path}`, {
      method,
      headers,
      body: body !== undefined ? JSON.stringify(body) : undefined,
    });
    if (res.status === 503) throw new Error('sfu-not-configured');
    const parsed = (await res.json().catch(() => ({}))) as SfuResponse;
    if (!res.ok || parsed.errorCode) {
      throw new Error(`SFU ${path}: ${parsed.errorDescription ?? res.status}`);
    }
    return parsed;
  }

  /** Serialize SDP negotiations — concurrent renegotiations corrupt state. */
  private locked<T>(fn: () => Promise<T>): Promise<T> {
    const next = this.queue.then(fn, fn);
    this.queue = next.catch(() => {});
    return next;
  }

  /** Returns false when the SFU isn't configured (placeholder mode). */
  async connect(): Promise<boolean> {
    try {
      const res = await this.sfu('/sessions/new');
      if (!res.sessionId) return false;
      this.sessionId = res.sessionId;
    } catch (err) {
      if (err instanceof Error && err.message === 'sfu-not-configured') return false;
      throw err;
    }

    this.pc = new RTCPeerConnection({
      iceServers: [{ urls: 'stun:stun.cloudflare.com:3478' }],
      bundlePolicy: 'max-bundle',
    });
    this.pc.ontrack = (e) => {
      const mid = e.transceiver.mid;
      const meta = mid ? this.pendingMids.get(mid) : undefined;
      if (!meta) return;
      e.track.onmute = () => this.onRemoteTrackLive?.(meta.participantKey, meta.trackName, false);
      e.track.onunmute = () => this.onRemoteTrackLive?.(meta.participantKey, meta.trackName, true);
      e.track.onended = () => this.onRemoteTrackLive?.(meta.participantKey, meta.trackName, false);
      this.onRemoteTrack?.({
        participantKey: meta.participantKey,
        trackName: meta.trackName,
        stream: new MediaStream([e.track]),
        kind: e.track.kind,
      });
    };
    return true;
  }

  /** Publish tracks under `${prefix}-${kind}` names. Returns published names. */
  publish(stream: MediaStream, prefix: string): Promise<string[]> {
    return this.locked(async () => {
      const pc = this.pc;
      if (!pc || !this.sessionId) throw new Error('not connected');
      const transceivers = stream.getTracks().map((track) => ({
        track,
        tx: pc.addTransceiver(track, { direction: 'sendonly' }),
      }));
      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);
      const tracks = transceivers.map(({ track, tx }) => ({
        location: 'local',
        mid: tx.mid,
        trackName: `${prefix}-${track.kind}`,
      }));
      const res = await this.sfu(`/sessions/${this.sessionId}/tracks/new`, {
        sessionDescription: { sdp: pc.localDescription!.sdp, type: 'offer' },
        tracks,
      });
      if (res.sessionDescription) {
        await pc.setRemoteDescription(res.sessionDescription);
      }
      for (const { track, tx } of transceivers) {
        if (tx.mid) this.publishedMids.set(`${prefix}-${track.kind}`, tx.mid);
        this.publishedSenders.set(`${prefix}-${track.kind}`, tx.sender);
      }
      // Apply preview caps after negotiation settles.
      for (const { track, tx } of transceivers) {
        const limits = PUBLISH_LIMITS.find((l) => l.match(`${prefix}-${track.kind}`));
        if (!limits) continue;
        const params = tx.sender.getParameters();
        params.encodings = [
          {
            ...(params.encodings?.[0] ?? {}),
            maxBitrate: limits.maxBitrate,
            scaleResolutionDownBy: limits.scaleResolutionDownBy,
            maxFramerate: limits.maxFramerate,
          },
        ];
        tx.sender.setParameters(params).catch(() => {
          /* older browsers: full-rate preview is acceptable */
        });
      }
      return tracks.map((t) => t.trackName);
    });
  }

  /** Pull one remote track; delivery arrives via onRemoteTrack. */
  pull(remoteSessionId: string, trackName: string, participantKey: string): Promise<void> {
    const key = `${remoteSessionId}:${trackName}`;
    if (this.pulledKeys.has(key)) return Promise.resolve();
    this.pulledKeys.add(key);

    return this.locked(async () => {
      const pc = this.pc;
      if (!pc || !this.sessionId) throw new Error('not connected');
      const res = await this.sfu(`/sessions/${this.sessionId}/tracks/new`, {
        tracks: [{ location: 'remote', sessionId: remoteSessionId, trackName }],
      });
      const mid = res.tracks?.[0]?.mid;
      if (mid) this.pendingMids.set(mid, { participantKey, trackName });

      if (res.requiresImmediateRenegotiation && res.sessionDescription) {
        await pc.setRemoteDescription(res.sessionDescription);
        const answer = await pc.createAnswer();
        await pc.setLocalDescription(answer);
        await this.sfu(
          `/sessions/${this.sessionId}/renegotiate`,
          { sessionDescription: { sdp: answer.sdp, type: 'answer' } },
          'PUT',
        );
      }
    }).catch((err) => {
      this.pulledKeys.delete(key); // allow a retry on the next roster tick
      console.error(`pull ${trackName} failed`, err);
    });
  }

  /**
   * Swap the media behind an already-published track without touching
   * the SFU (same sender, same mid, same trackName) — the recovery path
   * when a camera/mic dies and is re-acquired.
   */
  async replaceTrack(trackName: string, newTrack: MediaStreamTrack): Promise<boolean> {
    const sender = this.publishedSenders.get(trackName);
    if (!sender) return false;
    await sender.replaceTrack(newTrack);
    return true;
  }

  /** Forget a pulled track so it can be pulled again (recovery re-pull). */
  forgetPull(remoteSessionId: string, trackName: string): void {
    this.pulledKeys.delete(`${remoteSessionId}:${trackName}`);
  }

  /** Stop publishing named tracks (stop-share / switch-share). */
  closeByName(trackNames: string[]): Promise<void> {
    return this.locked(async () => {
      if (!this.sessionId) return;
      const mids = trackNames.map((n) => this.publishedMids.get(n)).filter((m): m is string => !!m);
      if (mids.length === 0) return;
      await this.sfu(
        `/sessions/${this.sessionId}/tracks/close`,
        { tracks: mids.map((mid) => ({ mid })), force: true },
        'PUT',
      );
      for (const n of trackNames) this.publishedMids.delete(n);
    }).catch((err) => console.error('closeByName failed', err));
  }

  close(): void {
    this.pc?.close();
    this.pc = null;
    this.sessionId = null;
  }
}
