import type { PartStore, RecorderHandle, UploadProgress, UploadTransport } from './types';
import { ChunkBuffer, DEFAULT_PART_SIZE } from './buffer';
import { Uploader, type UploaderOptions } from './uploader';

export interface TrackPipelineOptions {
  trackId: string;
  store: PartStore;
  transport: UploadTransport;
  partSizeBytes?: number;
  uploader?: UploaderOptions;
  onProgress?: (p: UploadProgress) => void;
}

export interface TrackPipeline {
  /** Resolves when recording stopped AND every byte reached the server. */
  done: Promise<void>;
  /** Stop recording; upload continues until drained. */
  stop(): void;
}

/**
 * The whole engine in one place: recorder chunks are appended to the
 * buffer while the uploader concurrently drains sealed parts. Two loops,
 * one owner each, joined only by the buffer.
 */
export function runTrackPipeline(recorder: RecorderHandle, opts: TrackPipelineOptions): TrackPipeline {
  const partSize = opts.partSizeBytes ?? DEFAULT_PART_SIZE;

  const done = (async () => {
    const buffer = await ChunkBuffer.open(opts.store, opts.trackId, partSize);
    const uploader = new Uploader(buffer, opts.transport, {
      ...opts.uploader,
      onProgress: opts.onProgress,
    });

    const recording = (async () => {
      for await (const blob of recorder.chunks) {
        await buffer.append(new Uint8Array(await blob.arrayBuffer()));
        // Report every chunk so the UI moves within seconds, not only
        // when a whole part finishes uploading.
        const s = buffer.state;
        opts.onProgress?.({
          trackId: s.trackId,
          bytesRecorded: s.bytesRecorded,
          bytesUploaded: s.bytesUploaded,
          uploadedParts: s.uploaded.length,
          sealedParts: s.sealedThrough,
          finished: s.finished,
          completed: false,
        });
      }
      await buffer.finish();
    })();

    const uploading = uploader.run();
    await Promise.all([recording, uploading]);
  })();

  return {
    done,
    stop: () => recorder.stop(),
  };
}

/**
 * Resume a previous track after a reload: no recorder involved, just
 * drain whatever the manifest says is still local.
 */
export async function resumeTrackUpload(opts: Omit<TrackPipelineOptions, 'partSizeBytes'>): Promise<void> {
  const existing = await opts.store.readManifest(opts.trackId);
  if (!existing) return;
  const buffer = await ChunkBuffer.open(opts.store, opts.trackId);
  // The recording is over (the page died with it) — seal what's left so
  // the uploader can drain to 100% instead of waiting for more chunks.
  await buffer.finish();
  const uploader = new Uploader(buffer, opts.transport, { ...opts.uploader, onProgress: opts.onProgress });
  await uploader.run();
}
