import {
  record,
  runTrackPipeline,
  resumeTrackUpload,
  HttpUploadTransport,
  OpfsPartStore,
  MemoryPartStore,
  type PartStore,
  type TrackPipeline,
  type UploadProgress,
} from '@recorder/capture';
import type { Api, Track } from './api';

const PENDING_KEY = 'vr.pendingUploads';

export interface PendingUpload {
  trackId: string;
  joinToken: string;
}

function storageOrNull(storage?: Storage): Storage | null {
  if (storage) return storage;
  return typeof localStorage === 'undefined' ? null : localStorage;
}

export function readPending(storage?: Storage): PendingUpload[] {
  const s = storageOrNull(storage);
  if (!s) return [];
  try {
    const raw = s.getItem(PENDING_KEY);
    return raw ? (JSON.parse(raw) as PendingUpload[]) : [];
  } catch {
    return [];
  }
}

export function addPending(entry: PendingUpload, storage?: Storage): void {
  const s = storageOrNull(storage);
  if (!s) return;
  const list = readPending(s).filter((p) => p.trackId !== entry.trackId);
  list.push(entry);
  s.setItem(PENDING_KEY, JSON.stringify(list));
}

export function removePending(trackId: string, storage?: Storage): void {
  const s = storageOrNull(storage);
  if (!s) return;
  s.setItem(PENDING_KEY, JSON.stringify(readPending(s).filter((p) => p.trackId !== trackId)));
}

function makeStore(): PartStore {
  return OpfsPartStore.isSupported() ? new OpfsPartStore() : new MemoryPartStore();
}

interface LocksApi {
  request(name: string, opts: { ifAvailable: boolean }, cb: (lock: unknown) => Promise<unknown>): Promise<unknown>;
}

/**
 * Cross-tab safety. Tabs share localStorage and OPFS, so without this a
 * second tab's resume logic would "finish" a track another tab is still
 * actively recording. A live tab holds a Web Lock per track; locks
 * auto-release when the tab dies, which is exactly the crash signal
 * resume needs. Returns 'locked' when another tab owns the track.
 */
export async function withTrackLock<T>(trackId: string, fn: () => Promise<T>, locksOverride?: LocksApi | null): Promise<T | 'locked'> {
  const locks = locksOverride ?? (typeof navigator !== 'undefined' ? (navigator.locks as unknown as LocksApi) : undefined);
  if (!locks) return fn();
  return (await locks.request(`vr.track.${trackId}`, { ifAvailable: true }, async (lock) => {
    if (!lock) return 'locked' as const;
    return fn();
  })) as T | 'locked';
}

const BITRATES: Partial<Record<Track['kind'], number>> = {
  cam: 2_500_000,
  screen: 4_000_000,
  // Board capture pans constantly (every pixel changes every frame) —
  // 4 Mbps macroblocks badly during movement. 8 Mbps at 1080p30 holds up.
  game: 8_000_000,
};

/**
 * Screen/tab captures change resolution mid-recording (window resizes),
 * which avc1 MP4 forbids — Chrome warns and may corrupt the file. avc3
 * carries in-band parameter sets and tolerates it. Cams keep the default
 * (fixed resolution; avc1 has the widest editor support).
 */
function mimeTypeFor(kind: Track['kind']): string | undefined {
  if (kind !== 'screen' && kind !== 'game') return undefined;
  if (typeof MediaRecorder === 'undefined') return undefined;
  for (const candidate of ['video/mp4;codecs=avc3.42E01E,mp4a.40.2', 'video/mp4;codecs=avc3.42E01E']) {
    if (MediaRecorder.isTypeSupported(candidate)) return candidate;
  }
  return undefined;
}

/**
 * Owns every active recording for the current participant. One controller
 * per call. Progress is polled by the UI via totals(), not pushed through
 * events.
 */
export class RecordingController {
  private readonly store = makeStore();
  private readonly pipelines: { trackId: string; kind: Track['kind']; pipeline: TrackPipeline }[] = [];
  readonly progress = new Map<string, UploadProgress>();
  onUpdate: (() => void) | null = null;
  /** First pipeline failure, surfaced to the UI instead of swallowed. */
  error: string | null = null;

  constructor(
    private readonly apiClient: Api,
    private readonly joinToken: string,
    private readonly apiBase = '',
  ) {}

  get active(): boolean {
    return this.pipelines.length > 0;
  }

  async start(kind: Track['kind'], stream: MediaStream): Promise<string> {
    const handle = record(stream, { timesliceMs: 3000, videoBitsPerSecond: BITRATES[kind], mimeType: mimeTypeFor(kind) });
    const { track } = await this.apiClient.createTrack(this.joinToken, kind, handle.mimeType || 'video/webm');
    addPending({ trackId: track.id, joinToken: this.joinToken });

    const pipeline = runTrackPipeline(handle, {
      trackId: track.id,
      store: this.store,
      transport: new HttpUploadTransport(this.apiBase, this.joinToken),
      onProgress: (p) => {
        this.progress.set(track.id, p);
        this.onUpdate?.();
      },
    });
    // Hold this track's cross-tab lock for the pipeline's whole life so no
    // other tab's resume can touch it while we're recording/uploading.
    if (typeof navigator !== 'undefined' && navigator.locks) {
      navigator.locks.request(`vr.track.${track.id}`, () => pipeline.done.catch(() => {})).catch(() => {});
    }
    pipeline.done
      .then(() => {
        removePending(track.id);
        return this.store.deleteTrack(track.id);
      })
      .catch((err) => {
        // Stays in the pending registry; resume retries on next visit.
        console.error(`upload pipeline failed for ${kind} track ${track.id}`, err);
        this.error = `${kind} upload failed: ${err instanceof Error ? err.message : String(err)}`;
        this.onUpdate?.();
      });
    this.pipelines.push({ trackId: track.id, kind, pipeline });
    return track.id;
  }

  /** Stop recording; uploads keep draining. */
  stopAll(): void {
    for (const p of this.pipelines) p.pipeline.stop();
  }

  /** Resolves when every pipeline drained to the server. */
  async waitAll(): Promise<void> {
    await Promise.allSettled(this.pipelines.map((p) => p.pipeline.done));
  }

  totals(): { recorded: number; uploaded: number; completed: number; tracks: number } {
    let recorded = 0;
    let uploaded = 0;
    let completed = 0;
    for (const p of this.progress.values()) {
      recorded += p.bytesRecorded;
      uploaded += p.bytesUploaded;
      if (p.completed) completed += 1;
    }
    return { recorded, uploaded, completed, tracks: this.pipelines.length };
  }
}

/**
 * Called on every app load: any track that never reached 100% (closed tab,
 * crash) drains now from OPFS. This is the resume story of phase 1.
 */
export async function resumePendingUploads(apiBase = ''): Promise<{ resumed: number; remaining: number }> {
  if (!OpfsPartStore.isSupported()) return { resumed: 0, remaining: readPending().length };
  const store = new OpfsPartStore();
  let resumed = 0;
  for (const entry of readPending()) {
    try {
      const result = await withTrackLock(entry.trackId, async () => {
        await resumeTrackUpload({
          trackId: entry.trackId,
          store,
          transport: new HttpUploadTransport(apiBase, entry.joinToken),
        });
        await store.deleteTrack(entry.trackId);
        removePending(entry.trackId);
        return 'done';
      });
      if (result === 'locked') continue; // another tab is live-recording this track
      resumed += 1;
    } catch {
      /* still offline or token expired — keep for next time */
    }
  }
  return { resumed, remaining: readPending().length };
}

export function formatBytes(n: number): string {
  if (n < 1024 * 1024) return `${Math.round(n / 1024)} KB`;
  if (n < 1024 * 1024 * 1024) return `${(n / (1024 * 1024)).toFixed(1)} MB`;
  return `${(n / (1024 * 1024 * 1024)).toFixed(2)} GB`;
}
