export interface User {
  id: string;
  email: string;
  plan?: string;
  role?: string;
}

export interface Session {
  id: string;
  name: string;
  invite_token: string;
  status: 'lobby' | 'recording' | 'ended';
  created_at: string;
  /** Set while a deletion is pending; the session purges after purge_after. */
  deleted_at?: string | null;
  purge_after?: string | null;
  project_id?: string | null;
}

export interface Project {
  id: string;
  name: string;
  created_at: string;
  /** Live (non-deleted) sessions in this project. */
  sessions_count: number;
}

export interface Participant {
  id: string;
  display_name: string;
  /** Host-enforced recording controls (roster endpoint only). */
  mic_muted?: boolean;
  cam_muted?: boolean;
  /** Live-call signaling (roster endpoint only). */
  rtc_session_id?: string | null;
  published?: string[];
}

export interface Track {
  id: string;
  participant_id: string;
  kind: 'cam' | 'screen' | 'mic' | 'game';
  status: 'recording' | 'complete';
  bytes_uploaded: number;
  /** Server-clock recording start — present on the session detail endpoint. */
  started_at?: string;
  completed_at?: string | null;
}

export interface ApiToken {
  id: string;
  label: string;
  created_at: string;
  last_used_at: string | null;
}

export interface AccountUsage {
  storage_bytes: number;
  storage_by_kind: Record<Track['kind'], number>;
  sessions_total: number;
  recording_seconds_total: number;
  recording_seconds_this_month: number;
}

export interface Roster {
  session: { id: string; name: string; status: Session['status'] };
  you: { participant_id: string; is_owner: boolean };
  participants: Participant[];
  tracks: Track[];
}

export class ApiError extends Error {
  constructor(
    public readonly status: number,
    message: string,
  ) {
    super(message);
  }
}

/**
 * Talks to the platform API. Framework-agnostic — this is the same class
 * our own web app, a Foundry module, or any other integration uses.
 *
 * Two auth modes, matching the server's per-origin CORS policy:
 * - Cookie (our own web app, same site): default, no `bearer`/`token` set.
 * - Bearer token (a personal API token, or a join token per-call — any
 *   other origin): pass `token` to the constructor for "always use this
 *   token", or `bearer` per-call for one-off join-token calls. Bearer
 *   requests never send credentials — a CORS response for an arbitrary
 *   origin can't safely grant cookie access, and a bearer token doesn't
 *   need it.
 */
export class Api {
  constructor(
    private readonly base = '',
    private readonly fetchFn: typeof fetch = (...args) => fetch(...args),
    private readonly defaultBearer?: string,
    /**
     * Cookie mode — ONLY for our own web app, whose origin gets a
     * credentialed CORS response. Everyone else (SDK consumers on any
     * other origin) must stay cookie-less: browsers reject a
     * credentialed request whose CORS response doesn't grant
     * Allow-Credentials, which is exactly what public endpoints like
     * join() hit from a Foundry server. Found live by integrator #1.
     */
    private readonly useCookies = false,
  ) {}

  private async req<T>(method: string, path: string, opts: { json?: unknown; bearer?: string } = {}): Promise<T> {
    const headers: Record<string, string> = {};
    if (opts.json !== undefined) headers['content-type'] = 'application/json';
    const bearer = opts.bearer ?? this.defaultBearer;
    if (bearer) headers['authorization'] = `Bearer ${bearer}`;
    const res = await this.fetchFn(`${this.base}${path}`, {
      method,
      headers,
      credentials: !bearer && this.useCookies ? 'include' : 'omit',
      body: opts.json !== undefined ? JSON.stringify(opts.json) : undefined,
    });
    const body = (await res.json().catch(() => ({}))) as Record<string, unknown>;
    if (!res.ok) throw new ApiError(res.status, typeof body.error === 'string' ? body.error : `request failed (${res.status})`);
    return body as T;
  }

  // auth
  signup(email: string, password: string) {
    return this.req<{ user: User }>('POST', '/v1/auth/signup', { json: { email, password } });
  }
  login(email: string, password: string) {
    return this.req<{ user: User }>('POST', '/v1/auth/login', { json: { email, password } });
  }
  logout() {
    return this.req<{ ok: true }>('POST', '/v1/auth/logout');
  }
  me() {
    return this.req<{ user: User }>('GET', '/v1/auth/me');
  }

  // sessions (owner)
  // projects
  listProjects() {
    return this.req<{ projects: Project[] }>('GET', '/v1/projects');
  }
  createProject(name: string) {
    return this.req<{ project: Project }>('POST', '/v1/projects', { json: { name } });
  }
  renameProject(id: string, name: string) {
    return this.req<{ ok: true }>('PATCH', `/v1/projects/${id}`, { json: { name } });
  }
  /** Ungroups the project's sessions; recordings are untouched. */
  deleteProject(id: string) {
    return this.req<{ ok: true }>('DELETE', `/v1/projects/${id}`);
  }
  setSessionProject(sessionId: string, projectId: string | null) {
    return this.req<{ ok: true }>('PATCH', `/v1/sessions/${sessionId}`, { json: { projectId } });
  }

  /** All sessions, or only one project's (deleted-pending included either way). */
  listSessions(projectId?: string) {
    return this.req<{ sessions: Session[] }>('GET', projectId ? `/v1/sessions?project=${encodeURIComponent(projectId)}` : '/v1/sessions');
  }
  createSession(name: string, projectId?: string) {
    return this.req<{ session: Session }>('POST', '/v1/sessions', { json: projectId ? { name, projectId } : { name } });
  }
  getSession(id: string) {
    return this.req<{ session: Session; participants: Participant[]; tracks: Track[] }>('GET', `/v1/sessions/${id}`);
  }
  deleteSession(id: string, confirmName: string) {
    return this.req<{ ok: true }>('DELETE', `/v1/sessions/${id}`, { json: { confirmName } });
  }
  /** Undo a pending deletion (any time inside the grace period). */
  restoreSession(id: string) {
    return this.req<{ ok: true }>('POST', `/v1/sessions/${id}/restore`);
  }
  startSession(id: string) {
    return this.req<{ ok: true }>('POST', `/v1/sessions/${id}/start`);
  }
  endSession(id: string) {
    return this.req<{ ok: true }>('POST', `/v1/sessions/${id}/end`);
  }
  /** Stop recording AND disconnect everyone from the live call. */
  closeSession(id: string) {
    return this.req<{ ok: true }>('POST', `/v1/sessions/${id}/close`);
  }
  rotateInvite(id: string) {
    return this.req<{ invite_token: string }>('POST', `/v1/sessions/${id}/rotate-invite`);
  }
  setParticipantControls(sessionId: string, participantId: string, controls: { micMuted?: boolean; camMuted?: boolean }) {
    return this.req<{ ok: true }>('POST', `/v1/sessions/${sessionId}/participants/${participantId}/controls`, { json: controls });
  }

  // join flow (public)
  joinInfo(inviteToken: string) {
    return this.req<{ session: { id: string; name: string; status: string } }>('GET', `/v1/join/${inviteToken}`);
  }
  join(inviteToken: string, displayName: string) {
    return this.req<{ participant: Participant; session: { id: string; name: string }; join_token: string }>(
      'POST',
      `/v1/join/${inviteToken}`,
      { json: { displayName } },
    );
  }

  // room + tracks (join token)
  roster(sessionId: string, joinToken: string) {
    return this.req<Roster>('GET', `/v1/rooms/${sessionId}/roster`, { bearer: joinToken });
  }
  createTrack(joinToken: string, kind: Track['kind'], mimeType: string) {
    return this.req<{ track: { id: string } }>('POST', '/v1/tracks', { bearer: joinToken, json: { kind, mimeType } });
  }
  setRtc(sessionId: string, joinToken: string, rtcSessionId: string, published: string[]) {
    return this.req<{ ok: true }>('POST', `/v1/rooms/${sessionId}/rtc`, {
      bearer: joinToken,
      json: { rtcSessionId, published },
    });
  }
  /** Upload client diagnostics (connection events) for the session owner to inspect. */
  postLogs(sessionId: string, joinToken: string, logs: { ts?: string; level?: string; event: string; detail?: string }[]) {
    return this.req<{ ok: true; stored: number }>('POST', `/v1/rooms/${sessionId}/logs`, {
      bearer: joinToken,
      json: { logs },
    });
  }
  /** Owner: read participants' diagnostics for a session. */
  sessionLogs(sessionId: string) {
    return this.req<{ logs: { participant_id: string; ts: string; level: string; event: string; detail: string | null }[] }>(
      'GET',
      `/v1/sessions/${sessionId}/logs`,
    );
  }

  // downloads (owner)
  downloadUrl(trackId: string) {
    return this.req<{ url: string }>('POST', `/v1/tracks/${trackId}/download-url`);
  }

  // personal API tokens
  createApiToken(label: string) {
    return this.req<{ token: { id: string; label: string; token: string } }>('POST', '/v1/auth/tokens', { json: { label } });
  }
  listApiTokens() {
    return this.req<{ tokens: ApiToken[] }>('GET', '/v1/auth/tokens');
  }
  revokeApiToken(id: string) {
    return this.req<{ ok: true }>('DELETE', `/v1/auth/tokens/${id}`);
  }

  // account
  accountUsage() {
    return this.req<{ usage: AccountUsage }>('GET', '/v1/account/usage');
  }
}
