import type { UploadTransport } from './types';

/**
 * Talks to the Worker API. Parts are PUT through the Worker to R2 — no
 * cloud credentials in the browser, just the short-lived join token.
 */
export class HttpUploadTransport implements UploadTransport {
  constructor(
    private readonly baseUrl: string,
    private readonly joinToken: string,
    // Wrapped, not a bare `fetch` reference: calling a bare reference as a
    // method rebinds `this` and browsers throw "Illegal invocation".
    private readonly fetchFn: typeof fetch = (...args) => fetch(...args),
  ) {}

  private headers(): Record<string, string> {
    return { authorization: `Bearer ${this.joinToken}` };
  }

  async uploadPart(
    trackId: string,
    partNumber: number,
    data: Uint8Array,
    isFinal: boolean,
    onBytes?: (sent: number) => void,
  ): Promise<void> {
    const url = `${this.baseUrl}/v1/tracks/${trackId}/parts/${partNumber}${isFinal ? '?final=1' : ''}`;
    // Browsers: XHR reports in-flight upload bytes (fetch cannot), which is
    // what keeps the progress bar moving during a 5 MiB part.
    if (typeof XMLHttpRequest !== 'undefined') {
      return new Promise<void>((resolve, reject) => {
        const xhr = new XMLHttpRequest();
        xhr.open('PUT', url);
        xhr.setRequestHeader('authorization', `Bearer ${this.joinToken}`);
        xhr.setRequestHeader('content-type', 'application/octet-stream');
        xhr.upload.onprogress = (e) => onBytes?.(e.loaded);
        xhr.onload = () =>
          xhr.status >= 200 && xhr.status < 300
            ? resolve()
            : reject(new Error(`uploadPart ${partNumber} failed: ${xhr.status}`));
        xhr.onerror = () => reject(new Error(`uploadPart ${partNumber} network error`));
        xhr.send(data.slice().buffer as ArrayBuffer);
      });
    }
    const res = await this.fetchFn(url, {
      method: 'PUT',
      headers: { ...this.headers(), 'content-type': 'application/octet-stream' },
      body: data.slice().buffer as ArrayBuffer,
    });
    if (!res.ok) throw new Error(`uploadPart ${partNumber} failed: ${res.status}`);
  }

  async completeTrack(trackId: string): Promise<void> {
    const res = await this.fetchFn(`${this.baseUrl}/v1/tracks/${trackId}/complete`, {
      method: 'POST',
      headers: this.headers(),
    });
    if (!res.ok) throw new Error(`completeTrack failed: ${res.status}`);
  }

  async remoteParts(trackId: string): Promise<number[]> {
    const res = await this.fetchFn(`${this.baseUrl}/v1/tracks/${trackId}`, { headers: this.headers() });
    if (!res.ok) throw new Error(`remoteParts failed: ${res.status}`);
    const body = (await res.json()) as { track: { uploaded_parts: number[] } };
    return body.track.uploaded_parts ?? [];
  }
}
