/**
 * Remembers "who am I in this session" per session, so refreshing the page
 * or coming back later rejoins as the same participant instead of minting
 * a new one every time.
 */
export interface StoredJoin {
  sessionId: string;
  sessionName: string;
  joinToken: string;
  participantId: string;
  displayName: string;
}

const key = (sessionId: string) => `vr.join.${sessionId}`;

function storageOrNull(storage?: Storage): Storage | null {
  if (storage) return storage;
  return typeof localStorage === 'undefined' ? null : localStorage;
}

export function readJoin(sessionId: string, storage?: Storage): StoredJoin | null {
  const s = storageOrNull(storage);
  if (!s) return null;
  try {
    const raw = s.getItem(key(sessionId));
    return raw ? (JSON.parse(raw) as StoredJoin) : null;
  } catch {
    return null;
  }
}

export function saveJoin(join: StoredJoin, storage?: Storage): void {
  storageOrNull(storage)?.setItem(key(join.sessionId), JSON.stringify(join));
}

export function clearJoin(sessionId: string, storage?: Storage): void {
  storageOrNull(storage)?.removeItem(key(sessionId));
}
