import type { RecorderHandle } from './types';

export interface RecorderOptions {
  timesliceMs?: number;
  videoBitsPerSecond?: number;
  audioBitsPerSecond?: number;
  mimeType?: string;
}

// H.264 MP4 first: universally supported by video editors (DaVinci,
// Premiere). Browsers without MP4 recording (Firefox) fall back to WebM.
const VIDEO_MIME_PREFERENCE = [
  'video/mp4;codecs=avc1.42E01E,mp4a.40.2',
  'video/mp4',
  'video/webm;codecs=vp9,opus',
  'video/webm;codecs=vp8,opus',
  'video/webm',
];

const AUDIO_MIME_PREFERENCE = ['audio/webm;codecs=opus', 'audio/webm', 'audio/mp4'];

export function pickMimeType(hasVideo: boolean, recorderCtor: typeof MediaRecorder = MediaRecorder): string {
  const candidates = hasVideo ? VIDEO_MIME_PREFERENCE : AUDIO_MIME_PREFERENCE;
  for (const c of candidates) {
    if (recorderCtor.isTypeSupported(c)) return c;
  }
  return '';
}

export function fileExtensionFor(mimeType: string): string {
  return mimeType.includes('mp4') ? 'mp4' : 'webm';
}

/**
 * Wraps MediaRecorder as an async iterable of chunks. The recording keeps
 * one constant bitrate regardless of network conditions — that is the whole
 * reason local recording beats saving the live call.
 */
export function record(
  stream: MediaStream,
  opts: RecorderOptions = {},
  recorderCtor: typeof MediaRecorder = MediaRecorder,
): RecorderHandle {
  const hasVideo = stream.getVideoTracks().length > 0;
  const mimeType = opts.mimeType ?? pickMimeType(hasVideo, recorderCtor);

  const recorder = new recorderCtor(stream, {
    mimeType: mimeType || undefined,
    videoBitsPerSecond: opts.videoBitsPerSecond ?? (hasVideo ? 2_500_000 : undefined),
    audioBitsPerSecond: opts.audioBitsPerSecond ?? 128_000,
  });

  const queue: Blob[] = [];
  let done = false;
  let error: Error | null = null;
  let wake: (() => void) | null = null;

  const notify = () => {
    wake?.();
    wake = null;
  };

  recorder.ondataavailable = (e: BlobEvent) => {
    if (e.data && e.data.size > 0) queue.push(e.data);
    notify();
  };
  recorder.onstop = () => {
    done = true;
    notify();
  };
  recorder.onerror = (e: Event) => {
    error = (e as unknown as { error?: Error }).error ?? new Error('MediaRecorder error');
    done = true;
    notify();
  };

  recorder.start(opts.timesliceMs ?? 3000);

  const chunks: AsyncIterable<Blob> = {
    async *[Symbol.asyncIterator]() {
      for (;;) {
        while (queue.length > 0) yield queue.shift()!;
        if (error) throw error;
        if (done) return;
        await new Promise<void>((r) => {
          wake = r;
        });
      }
    },
  };

  return {
    chunks,
    mimeType: mimeType || recorder.mimeType,
    stop() {
      if (recorder.state !== 'inactive') recorder.stop();
    },
  };
}
