import { Api, type Roster, type Track } from './api';
import { RtcClient, type RemoteTrack } from './rtc';
import { connectRoomSocket, type RoomSocket } from './roomSocket';
import { RecordingController } from './recording';
import { Emitter } from './events';

/** The slice of RtcClient that Room actually uses — lets tests inject a fake. */
export interface RtcLike {
  sessionId: string | null;
  onRemoteTrack: ((t: RemoteTrack) => void) | null;
  onRemoteTrackLive: ((participantKey: string, trackName: string, live: boolean) => void) | null;
  connect(): Promise<boolean>;
  publish(stream: MediaStream, prefix: string): Promise<string[]>;
  pull(remoteSessionId: string, trackName: string, participantKey: string): Promise<void>;
  closeByName(trackNames: string[]): Promise<void>;
  close(): void;
  replaceTrack?(trackName: string, newTrack: MediaStreamTrack): Promise<boolean>;
  forgetPull?(remoteSessionId: string, trackName: string): void;
}

/** The slice of RecordingController that Room actually uses. */
export interface RecorderLike {
  error: string | null;
  start(kind: Track['kind'], stream: MediaStream): Promise<string>;
  stopAll(): void;
  waitAll(): Promise<void>;
  totals(): { recorded: number; uploaded: number; completed: number; tracks: number };
}

export type RoomEvents = {
  /** Full roster refresh — participants, session status, track progress. */
  roster: (roster: Roster) => void;
  /** Who currently has a live socket open (tab closed/crashed → removed within ~15s, usually faster). */
  presence: (onlineParticipantIds: Set<string>) => void;
  /** A remote participant's stream became available. kind is 'cam' | 'screen' | 'mic' | 'game'. */
  stream: (participantId: string, kind: string, trackName: string, stream: MediaStream) => void;
  /** A remote stream's packets stopped (~1-2s) or resumed — reversible, not a departure. */
  streamLive: (participantId: string, kind: string, trackName: string, live: boolean) => void;
  /** A host-issued control message, e.g. 'close' (session ended for everyone). */
  control: (action: string) => void;
};

export interface RoomIdentity {
  apiBase?: string;
  sessionId: string;
  joinToken: string;
  participantId: string;
  displayName: string;
}

/** Injectable factories — tests substitute fakes; real consumers never need to touch this. */
export interface RoomDeps {
  connectSocket?: typeof connectRoomSocket;
  createRtc?: (joinToken: string, apiBase: string) => RtcLike;
  createRecorder?: (api: Api, joinToken: string, apiBase: string) => RecorderLike;
  createApi?: (apiBase: string) => Api;
}

/**
 * One participant's view of a live session: roster/presence, the live
 * call (publish/pull), and local recording. Deliberately two separate
 * capabilities under one roof — publishing to the call and recording are
 * independent, exactly like the rest of this platform: the call is a
 * disposable preview, the recording is the product.
 *
 * Host-only actions (start/stop recording for everyone, mute another
 * participant, delete the session) are NOT here — those require the
 * host's own credentials (a personal API token or their login), and live
 * on `RecorderClient`. A host who also wants their own camera recorded
 * joins a Room the same way any participant does.
 */
export class Room extends Emitter<RoomEvents> {
  readonly sessionId: string;
  readonly participantId: string;
  readonly displayName: string;

  private readonly api: Api;
  private readonly apiBase: string;
  private readonly joinToken: string;
  private socket: RoomSocket | null = null;
  private rtc: RtcLike | null = null;
  private recorder: RecorderLike | null = null;
  private publishedByPrefix = new Map<string, string[]>();
  private latestRoster: Roster | null = null;
  private onlineIds: Set<string> | null = null;
  /** `${pid}:${trackName}` -> epoch ms when its packets stopped. */
  private staleSince = new Map<string, number>();
  private recoveryTimer: ReturnType<typeof setInterval> | null = null;
  private logBuffer: { ts: string; level: string; event: string; detail?: string }[] = [];
  private logTimer: ReturnType<typeof setInterval> | null = null;

  private constructor(
    identity: RoomIdentity,
    private readonly deps: RoomDeps = {},
  ) {
    super();
    this.sessionId = identity.sessionId;
    this.participantId = identity.participantId;
    this.displayName = identity.displayName;
    this.apiBase = identity.apiBase ?? '';
    this.joinToken = identity.joinToken;
    this.api = (deps.createApi ?? ((base) => new Api(base)))(this.apiBase);
  }

  /** Join via an invite link/token — mints a fresh participant identity. */
  static async join(opts: { apiBase?: string; inviteToken: string; displayName: string }, deps: RoomDeps = {}): Promise<Room> {
    const api = (deps.createApi ?? ((base) => new Api(base)))(opts.apiBase ?? '');
    const r = await api.join(opts.inviteToken, opts.displayName);
    const room = new Room(
      {
        apiBase: opts.apiBase,
        sessionId: r.session.id,
        joinToken: r.join_token,
        participantId: r.participant.id,
        displayName: opts.displayName,
      },
      deps,
    );
    room.connectSocket();
    return room;
  }

  /** Reconnect with an identity obtained earlier (e.g. restored from storage) — no re-join. */
  static resume(identity: RoomIdentity, deps: RoomDeps = {}): Room {
    const room = new Room(identity, deps);
    room.connectSocket();
    return room;
  }

  private connectSocket(): void {
    const connect = this.deps.connectSocket ?? connectRoomSocket;
    this.socket = connect(this.sessionId, this.joinToken, (payload) => this.handleMessage(payload), this.apiBase);
    this.logTimer = setInterval(() => this.flushLogs(), 10_000);
    this.log('info', 'joined', this.displayName);
  }

  // ---- diagnostics: buffered client events the owner can inspect -------------

  /** Record a diagnostic event; batches upload every 10s (best-effort). */
  log(level: 'info' | 'warn' | 'error', event: string, detail?: unknown): void {
    this.logBuffer.push({
      ts: new Date().toISOString(),
      level,
      event,
      detail: detail === undefined ? undefined : typeof detail === 'string' ? detail : JSON.stringify(detail),
    });
    if (this.logBuffer.length >= 25) this.flushLogs();
  }

  private flushLogs(): void {
    if (this.logBuffer.length === 0) return;
    const batch = this.logBuffer.splice(0, 50);
    this.api.postLogs(this.sessionId, this.joinToken, batch).catch(() => {
      /* diagnostics are best-effort; never disrupt the session over them */
    });
  }

  private handleMessage(payload: unknown): void {
    const p = payload as { type?: string; session?: Roster['session']; participants?: Roster['participants']; tracks?: Roster['tracks']; online?: string[]; action?: string };
    if (p.type === 'roster' && p.session) {
      this.latestRoster = {
        session: p.session,
        participants: p.participants ?? [],
        tracks: p.tracks ?? [],
        you: this.latestRoster?.you ?? { participant_id: this.participantId, is_owner: false },
      };
      this.emit('roster', this.latestRoster);
    } else if (p.type === 'presence' && p.online) {
      this.onlineIds = new Set(p.online);
      this.emit('presence', this.onlineIds);
    } else if (p.type === 'control' && p.action) {
      this.emit('control', p.action);
    }
  }

  get roster(): Roster | null {
    return this.latestRoster;
  }
  get online(): Set<string> | null {
    return this.onlineIds;
  }
  /** Whether this participant is also the session's owner (host). */
  get isOwner(): boolean {
    return this.latestRoster?.you.is_owner ?? false;
  }

  /**
   * Connect to the live call. Returns false when the SFU isn't configured
   * server-side — recording still works fully either way.
   */
  async connectLiveCall(): Promise<boolean> {
    const rtc = (this.deps.createRtc ?? ((token, base) => new RtcClient(token, base)))(this.joinToken, this.apiBase);
    rtc.onRemoteTrack = ({ participantKey, trackName, stream }) => {
      this.staleSince.delete(`${participantKey}:${trackName}`);
      this.emit('stream', participantKey, kindOf(trackName), trackName, stream);
    };
    rtc.onRemoteTrackLive = (participantKey, trackName, live) => {
      const key = `${participantKey}:${trackName}`;
      if (live) {
        if (this.staleSince.delete(key)) this.log('info', 'stream-recovered', key);
      } else if (!this.staleSince.has(key)) {
        this.staleSince.set(key, Date.now());
        this.log('warn', 'stream-stale', key);
      }
      this.emit('streamLive', participantKey, kindOf(trackName), trackName, live);
    };
    const ok = await rtc.connect();
    this.log(ok ? 'info' : 'warn', 'live-call', ok ? 'connected' : 'unavailable');
    if (ok) {
      this.rtc = rtc;
      // Recovery loop: a track whose packets stopped but whose publisher
      // is still online and still announcing it gets re-pulled from the
      // SFU — a fresh subscription heals drops the cosmetic "stale" flag
      // alone never could.
      this.recoveryTimer = setInterval(() => this.recoverStaleTracks(), 5_000);
    }
    return ok;
  }

  private recoverStaleTracks(): void {
    if (!this.rtc) return;
    const now = Date.now();
    for (const [key, since] of this.staleSince) {
      if (now - since < 8_000) continue;
      const sep = key.indexOf(':');
      const pid = key.slice(0, sep);
      const trackName = key.slice(sep + 1);
      const p = this.latestRoster?.participants.find((x) => x.id === pid);
      const online = !this.onlineIds || this.onlineIds.has(pid);
      // Publisher gone or track withdrawn: presence/roster handles the UI.
      if (!p?.rtc_session_id || !online || !(p.published ?? []).includes(trackName)) continue;
      this.staleSince.set(key, now); // restart the window between attempts
      this.log('warn', 'repull', key);
      this.rtc.forgetPull?.(p.rtc_session_id, trackName);
      this.rtc.pull(p.rtc_session_id, trackName, pid);
    }
  }

  /**
   * Swap the media behind already-published tracks (same SFU track names,
   * no renegotiation) — the recovery path after a camera/mic died and was
   * re-acquired. Receivers notice nothing except the picture returning.
   */
  async replaceLocalStream(prefix: string, stream: MediaStream): Promise<void> {
    if (!this.rtc?.replaceTrack) return;
    for (const track of stream.getTracks()) {
      await this.rtc.replaceTrack(`${prefix}-${track.kind}`, track);
    }
    this.log('info', 'replace-local', prefix);
  }

  /**
   * Pull one participant's tracks of a given kind (e.g. only 'cam', never
   * 'screen') — this is how a consumer shows webcams without the map.
   */
  pull(participantId: string, kind: string): void {
    if (!this.rtc) return;
    const target = this.latestRoster?.participants.find((p) => p.id === participantId);
    if (!target?.rtc_session_id) return;
    for (const name of target.published ?? []) {
      if (kindOf(name) === kind) this.rtc.pull(target.rtc_session_id, name, participantId);
    }
  }

  /**
   * Publish a local stream (camera, screen, canvas — anything). Calling
   * this again with the same prefix atomically replaces what was
   * published under it and re-announces the new names, which is what
   * makes "switch share" visible to everyone instead of only the host.
   */
  async publish(stream: MediaStream, prefix: string): Promise<string[]> {
    if (!this.rtc) throw new Error('connectLiveCall() must succeed before publishing');
    const names = await this.rtc.publish(stream, prefix);
    this.publishedByPrefix.set(prefix, names);
    await this.announcePublished();
    return names;
  }

  async unpublish(prefix: string): Promise<void> {
    const names = this.publishedByPrefix.get(prefix);
    if (!names || !this.rtc) return;
    await this.rtc.closeByName(names);
    this.publishedByPrefix.delete(prefix);
    await this.announcePublished();
  }

  private async announcePublished(): Promise<void> {
    if (!this.rtc?.sessionId) return;
    const all = [...this.publishedByPrefix.values()].flat();
    await this.api.setRtc(this.sessionId, this.joinToken, this.rtc.sessionId, all);
  }

  // ---- recording: independent of the live call ------------------------------

  /** Start locally recording a stream at full quality; uploads as it records. */
  async startRecording(kind: Track['kind'], stream: MediaStream): Promise<string> {
    this.recorder ??= (this.deps.createRecorder ?? ((api, token, base) => new RecordingController(api, token, base)))(
      this.api,
      this.joinToken,
      this.apiBase,
    );
    return this.recorder.start(kind, stream);
  }

  /** Stop recording; uploads keep draining until waitForUploads() resolves. */
  stopRecording(): void {
    this.recorder?.stopAll();
  }

  async waitForUploads(): Promise<void> {
    await this.recorder?.waitAll();
  }

  recordingProgress(): { recorded: number; uploaded: number; completed: number; tracks: number } {
    return this.recorder?.totals() ?? { recorded: 0, uploaded: 0, completed: 0, tracks: 0 };
  }

  /** First recording pipeline failure, if any — surfaced instead of swallowed. */
  get recordingError(): string | null {
    return this.recorder?.error ?? null;
  }

  /** Tear down the live call and socket. Local camera/screen tracks are the caller's — stop those yourself. */
  leave(): void {
    this.log('info', 'left');
    this.flushLogs();
    if (this.recoveryTimer) clearInterval(this.recoveryTimer);
    this.recoveryTimer = null;
    if (this.logTimer) clearInterval(this.logTimer);
    this.logTimer = null;
    this.socket?.close();
    this.rtc?.close();
    this.recorder?.stopAll();
  }
}

function kindOf(trackName: string): string {
  return trackName.split('-')[0] ?? trackName;
}
